+    fn truncate_plain_to_width(&self, s: &str, max_visible: usize) -> String {
+        if max_visible == 0 {
+            return String::new();
+        }
+
+        let char_count = s.chars().count();
+        if char_count <= max_visible {
+            return s.to_string();
+        }
+
+        if max_visible <= 3 {
+            return ".".repeat(max_visible);
+        }
+
+        let truncated: String = s.chars().take(max_visible - 3).collect();
+        format!("{truncated}...")
+    }
